WITH owner AS (
  SELECT id FROM profiles WHERE LOWER(COALESCE(email, '')) IN ('jason@bouncingfish.com', 'jason.kneen@bouncingfish.com', 'jason.kneen@gmail.com')
  ORDER BY CASE LOWER(COALESCE(email, '')) WHEN 'jason@bouncingfish.com' THEN 0 WHEN 'jason.kneen@gmail.com' THEN 1 ELSE 2 END
  LIMIT 1
)
UPDATE worlds
SET owner_profile_id = owner.id, updated_at = NOW()
FROM owner
WHERE worlds.kind = 'starter'
  AND worlds.slug <> 'tinyverse-nexus'
  AND worlds.owner_profile_id IS DISTINCT FROM owner.id;
